var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 기계......","JPN":"ずっと考えてきたあのマシン……","ENG":"that this machine— ","TWN":"一直盤踞在你腦海中的那個機械……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"아니 그 아이야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"いや、あの子こそが、これから向き合う運命に必ず必要な存在であることを。","ENG":"No, this child, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"不，是那個孩子，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 아이와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであの子とともにいることを。","ENG":"that you'll be with this child, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和那個孩子一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called the child to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"으아, 우와앗! 비켜, 비켜!","JPN":"うわっ、うわぁ～！どいて、どいて！","ENG":" Woah, woah, woah! Out of the way!","TWN":"哇啊，哇啊啊！讓開、讓開！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"헤헤! 미안 아빠! 요즘 무게중심 잡는 연습을 해보고 있어서 말이야.","JPN":"へへっ！ごめんね、パパ！最近重心をとる練習をしてるんだ。","ENG":" Heh heh! Sorry, Daddy! I've been working on maintaining my balance.","TWN":"嘿嘿！對不起，爸爸！最近我在做平衡練習。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"얼마 전에 이 투영 홀로그램에도 질량을 부여할 수 있다는 걸 알게 됐거든!","JPN":"この前、この投影ホログラムにも質量を付与できるってことがわかったの！","ENG":" I recently learned that I can imbue mass in this hologram too!","TWN":"因為不久前，我發現這個全息影像投影可以賦予我質量！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"보여? 봤어? 이제 열쇠 정도는 이 손으로 직접 집는 것도 가능해!","JPN":"見える？見た？これで鍵ぐらいは手で直接取れるようになったの！","ENG":" See? Did you see that? I can grab a key with this hand now!","TWN":"看見了沒？看見了沒？現在我可以用這隻手直接抓住鑰匙了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"펜을 쥐어서 글씨를 쓸 수도 있고, 서랍을 당길 수도 있어! 어때?","JPN":"ペンを握って文字も書けるし、引き出しを引ける！どう？","ENG":" I can even write with a pen or open a drawer! What do you think?","TWN":"可以拿筆寫字，還可以拉開抽屜！怎麼樣啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"응? 그냥 로봇팔을 쓰면 되지 않냐고?","JPN":"うん？ロボットの腕を使えばいいじゃないかって？","ENG":" Huh? Why can't I just use my robot arm?","TWN":"嗯？你說直接用機械手臂就好了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"안돼, 안돼! 그러면 몸이 생기는 의미가 없어지잖아!","JPN":"だめ、だめ！それじゃ体ができる意味がないじゃん！","ENG":" That won't do at all! That defeats the whole purpose of having a humanoid body!","TWN":"不行、不行！那樣不是就失去擁有身體的意義了嗎！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"나도 뚜벅뚜벅하면서 걷고, 넘어져서 우당탕거리고, 코도 골고 싶어! 아빠처럼 말이야!","JPN":"私もこつこつ歩いて、バタンと転んで、いびきもかきたいもん！パパみたいに！","ENG":" I want to walk on two feet, trip and fall, and snore too! Just like you, Daddy!","TWN":"我也要像爸爸一樣！噔噔噔地走路，摔倒了匡噹匡噹地響，睡覺時打呼！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"그리고……!","JPN":"そして……！","ENG":" And also...","TWN":"還有……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"아! 아빠랑 숲으로 놀러 가고 싶어! 같이 손을 잡고서 말이야!","JPN":"そう！パパと森に遊びに行きたいの！一緒に手を繋いで！","ENG":" Oh! I want to go on a stroll in the forest with you! You and me together, holding hands!","TWN":"對了！我還想跟爸爸一起去森林裡玩！手牽著手去！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"숲의 요정을 만나서 다같이 행복해지게 해달라고 소원도 빌 거야!","JPN":"森の妖精に会って、みんなで幸せになれるようにって願い事もするの！","ENG":" Then I'll meet the forest fairy and make a wish for everyone to be happy!","TWN":"遇到森林裡的妖精後，向他們許願，讓大家都過上幸福的日子！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"……어려울 거라고?","JPN":"……それは難しいって？","ENG":" You think... that's not possible?","TWN":"……你說會很難？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"아냐! 절대 그렇지 않아!","JPN":"違う！全然そんなことない！","ENG":" You're wrong! You're completely wrong!","TWN":"不！絕對不會的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NULL_RECITAL","text":{"KOREA":"잘 봐! 이 도장도 내 손으로 직접 찍을 수 있는걸!","JPN":"よく見て！このハンコも、私の手で直接押せるもん！","ENG":" Look! I can even stamp this seal myself!","TWN":"看好了！我一定會親手蓋上這個印章的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_RECITAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};